#include <stdio.h>

void printRec(int n) {
    if (n == 1) {
        printf("1");
        return;
    }
    printRec(n - 1);
    printf(" %d", n);
}

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &N) != 1) return 0;
        if (N >= 1) printRec(N);
        printf("\n");
    }
    return 0;
}

